// Parse the LLM response and prepare data for Supabase update
const output = $input.first().json.output;

// Try to parse the JSON from the LLM response
let brief;
try {
  // Handle case where LLM wraps JSON in markdown code fences
  const cleaned = output.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  brief = JSON.parse(cleaned);
} catch (e) {
  throw new Error(`Failed to parse LLM response as JSON: ${e.message}\nRaw output: ${output}`);
}

// Generate slug from title
const slug = brief.title
  .toLowerCase()
  .replace(/[^a-z0-9\s-]/g, '')
  .replace(/\s+/g, '-')
  .replace(/-+/g, '-')
  .substring(0, 80);

// Prepare brief_json (without title — title goes in its own column)
const briefJson = {
  keyword: brief.keyword,
  outline: brief.outline,
  angle: brief.angle,
  audience: brief.audience,
  key_points: brief.key_points
};

return [{
  json: {
    article_id: $('Read Article').first().json.id,
    title: brief.title,
    slug: slug,
    brief_json: briefJson
  }
}];

